namespace sv_b05f23281cd84e038f967d8b67ef9660.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors = ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly List<string> AllTimeSlots =
        ["9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM", "11:00 AM", "1:00 PM", "1:30 PM", "2:00 PM", "2:30 PM", "3:00 PM"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return all slots for any doctor/date combination
        return Task.FromResult(new List<string>(AllTimeSlots));
    }

    /// <summary>
    /// Validates patient data server-side. Returns a dictionary of field name -> error message.
    /// Empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Reject email with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        // Reject "None" insurance with Dr. Smith (doesn't accept self-pay)
        if (insuranceProvider == "None" && string.Equals(doctor, "Dr. Smith", StringComparison.OrdinalIgnoreCase))
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Reject 10:00 AM as taken (simulates race condition)
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_b05f23281cd84e038f967d8b67ef9660.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* STEP 1: Patient Information *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.ContainsKey("Email"))
            {
                <div class="validation-message">@serverErrors["Email"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
        }
    </fieldset>

    @* STEP 2: Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor" @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.ContainsKey("Doctor"))
                {
                    <div class="validation-message">@serverErrors["Doctor"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label for="timeSlot" class="form-label">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.ContainsKey("TimeSlot"))
                {
                    <div class="validation-message">@serverErrors["TimeSlot"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
                Check Availability
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || serverErrors.Count > 0 || isSubmitting)">
                Book Appointment
            </button>

            @if (availabilityChecked && serverErrors.Count == 0)
            {
                <div class="alert alert-success mt-3">Availability confirmed! You may submit.</div>
            }
        </fieldset>
    }
</EditForm>

@if (appointmentBooked)
{
    <div class="alert alert-success mt-4">
        <strong>Appointment booked successfully!</strong> A confirmation will be sent to @Model.Email.
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool availabilityChecked;
    private bool appointmentBooked;
    private bool isSubmitting;
    private List<string> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
        editContext = new EditContext(Model);
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        var validationMessages = new ValidationMessageStore(editContext);

        // Validate step 1 fields manually
        bool isValid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            validationMessages.Add(editContext.Field(nameof(Model.PatientName)), "Patient Name is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            validationMessages.Add(editContext.Field(nameof(Model.Email)), "Email is required.");
            isValid = false;
        }
        else if (!System.ComponentModel.DataAnnotations.Validator.TryValidateProperty(
            Model.Email,
            new System.ComponentModel.DataAnnotations.ValidationContext(Model) { MemberName = nameof(Model.Email) },
            null))
        {
            validationMessages.Add(editContext.Field(nameof(Model.Email)), "Please enter a valid email address.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            validationMessages.Add(editContext.Field(nameof(Model.Phone)), "Phone is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            validationMessages.Add(editContext.Field(nameof(Model.InsuranceProvider)), "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            showStep2 = true;
            serverErrors.Clear();
            availabilityChecked = false;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
        else
        {
            availableSlots = [];
        }

        Model.TimeSlot = string.Empty;
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;
        isSubmitting = true;

        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email ?? string.Empty,
                Model.InsuranceProvider ?? string.Empty,
                Model.Doctor ?? string.Empty,
                Model.TimeSlot ?? string.Empty);

            serverErrors = errors;
            availabilityChecked = errors.Count == 0;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void HandleSubmit()
    {
        if (availabilityChecked && serverErrors.Count == 0)
        {
            appointmentBooked = true;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_b05f23281cd84e038f967d8b67ef9660.Models;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient Name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance Provider is required.")]
    public string? InsuranceProvider { get; set; }

    [Required(ErrorMessage = "Preferred Doctor is required.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time Slot is required.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason for visit must be 500 characters or fewer.")]
    public string? ReasonForVisit { get; set; }
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateTime date && date.Date <= DateTime.Today)
        {
            return new ValidationResult(ErrorMessage);
        }
        return ValidationResult.Success;
    }
}

